import { Card, Text, Image } from "@nextui-org/react";
import React from "react";
import Project from "../iconComponents/Project";
import Star from "../iconComponents/Star";
import User from "../iconComponents/User";

export default function FlipCard(props: { title: string; desc: any }) {
  return (
    <div>
      <Card
        isHoverable
        variant="bordered"
        css={{
          height: "250px",
          backgroundColor: "$purple600",
          margin: "auto",
        }}
      >
        <Card.Body
          className="card-front"
          css={{ ta: "center", justifyContent: "center" }}
        >
          <>
            <Text h5>{props.title}</Text>
          </>
        </Card.Body>
        <Card.Body
          className="card-back"
          css={{ ta: "center", justifyContent: "center" }}
        >
          <>
            <Text h5>{props.desc}</Text>
          </>
        </Card.Body>
      </Card>
    </div>
  );
}
